	c    int64
	color int64
}

// PriorityQueue implements heap.Interface and holds States.
// We prioritize minimum time, then maximum color (by negating color in comparison).
type PriorityQueue []*State

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	// Min-heap based on time
	if pq[i].time != pq[j].time {
		return pq[i].time < pq[j].time
	}
	// Tie-breaker: Max color (smaller negative value means larger positive color)
	return pq[i].color > pq[j].color
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*State)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(n int64, m int64, sources [][]int64) [][]int64 {
	N := int(n)
	M := int(m)

	// Time[r][c]: Minimum time to reach (r, c)
	// Initialize with a very large number representing infinity
	timeGrid := make([][]int64, N)
	for i := 0; i < N; i++ {
		timeGrid[i] = make([]int64, M)
		for j := 0; j < M; j++ {
			timeGrid[i][j] = math.MaxInt64
		}
	}

	// Color[r][c]: Best color achieved at the minimum time
	colorGrid := make([][]int64, N)
	for i := 0; i < N; i++ {
		colorGrid[i] = make([]int64, M)
		// Initialized to 0, which is the default uncolored state, but we use it to check for better colors
	}

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)

	// 1. Initialization: Seed the PQ with all sources
	for _, source := range sources {
		r, c, color := int(source[0]), int(source[1]), source[2]

		// Handle potential multiple sources at the same spot (though problem states they are unique locations)
		if 0 < timeGrid[r][c] {
			timeGrid[r][c] = 0
			colorGrid[r][c] = color
			heap.Push(&pq, &State{time: 0, r: int64(r), c: int64(c), color: color})
		} else if timeGrid[r][c] == 0 {
			// If it's already a source, take the maximum color
			if color > colorGrid[r][c] {
				colorGrid[r][c] = color
				// Re-pushing ensures that this better color propagates immediately at t=0
				heap.Push(&pq, &State{time: 0, r: int64(r), c: int64(c), color: color})
			}
		}
	}

	dr := []int64{-1, 1, 0, 0}
	dc := []int64{0, 0, -1, 1}

	// 2. Dijkstra/Multi-source BFS Loop
	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*State)
		t, r, c, C := current.time, current.r, current.c, current.color

		// Stale check: If we found a strictly faster path, or a path of same speed but better color, ignore.
		// Due to the PQ ordering (time ASC, color DESC), the first time we extract a state (t, r, c, C),
		// it represents the best possible arrival time and color combination found so far for (r, c).
		if t > timeGrid[r][c] || (t == timeGrid[r][c] && C < colorGrid[r][c]) {
			continue
		}

		// Explore neighbors
