				tPrime := t + 1
				CPrime := C

				tMin := timeGrid[nr][nc]
				cBest := colorGrid[nr][nc]

				// Case 1: Strictly faster path found
				if tPrime < tMin {
					timeGrid[nr][nc] = tPrime
					colorGrid[nr][nc] = CPrime
					heap.Push(&pq, &State{time: tPrime, r: nr, c: nc, color: CPrime})
				} else if tPrime == tMin {
					// Case 2: Time tie, check color
					if CPrime > cBest {
						// Found a better color at the current minimum time. Update and re-push.
						colorGrid[nr][nc] = CPrime
						heap.Push(&pq, &State{time: tPrime, r: nr, c: nc, color: CPrime})
					}
					// If CPrime <= cBest, do nothing.
				}
				// Case 3: tPrime > tMin, do nothing.
			}
		}
	}

