	result := make([][]int64, N)
	for i := 0; i < N; i++ {
		result[i] = make([]int64, M)
		for j := 0; j < M; j++ {
			// If timeGrid[i][j] is MaxInt64, it remains 0 (uncolored), which is correct.
			result[i][j] = colorGrid[i][j]
		}
	}

	return result
